module voltage_regulator (
    input [4:0] obf_Vin,
    output reg [4:0] Vout
);
    always @(*) begin
        if (obf_Vin < 5'd16) 
            Vout = obf_Vin;
        else if (obf_Vin < 5'd32) 
            Vout = 5'd16;
        else if (obf_Vin < 5'd48) 
            Vout = 5'd32;
        else 
            Vout = 5'd48;
    end
endmodule
